const GRACE=90*1000, T2=10*60*1000, T3=15*60*1000, T3_SLOW=60*60*1000, MULTI=3;
const CORE={'Home Assistant':1,'MQTT broker':1,'Pi-hole primary':1,'proxmox1':1,'proxmox2':1,'proxmox-remote':1,'TrueNAS':1,'MikroTik RB5009 (gateway)':1};
function dub(){return new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});}
function dhour(){return parseInt(new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',hour12:false}),10);}
function quiet(){var h=dhour();return (h>=22||h<7);}
function hhmm(ts){return new Date(ts).toLocaleTimeString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',minute:'2-digit'});}
function dur(ms){var m=Math.max(1,Math.round(ms/60000));if(m<60)return m+'m';return Math.floor(m/60)+'h'+(m%60)+'m';}
function durWords(ms){var m=Math.max(1,Math.round(ms/60000));var h=Math.floor(m/60),mm=m%60;var pp=[];if(h)pp.push(h+' hour'+(h>1?'s':''));if(mm||!h)pp.push(mm+' minute'+(mm===1?'':'s'));return pp.join(' and ');}
function phone(t,m,tag){if(global.get('maintenance_mode')){log('[maint-suppressed] '+t+' — '+m);return;}node.send([{title:t,message:m,ndata:{tag:tag||'infra',channel:'Infra'}},null,null]);}
function tts(m){if(global.get('maintenance_mode')){log('[maint-suppressed-tts] '+m);return;}node.send([null,{message:m},null]);}
function log(s){node.send([null,null,{payload:dub()+'  '+s+'\n'}]);}
function countDown(){return Object.keys(context.get('S')||{}).length;}
function clr(mon){var T=context.get('T')||{};var t=T[mon];if(t){if(t.grace)clearTimeout(t.grace);if(t.t2)clearTimeout(t.t2);if(t.t3)clearInterval(t.t3);delete T[mon];context.set('T',T);}}

if(msg && msg.topic==='flush'){
  var S=context.get('S')||{}, ON=context.get('ON')||[], lines=[];
  for(var m in S){lines.push('• '+m+' still DOWN since '+hhmm(S[m].downSince));}
  ON.filter(function(e){return e.type==='recovered';}).forEach(function(e){lines.push('• '+e.mon+' was down '+hhmm(e.from)+'–'+hhmm(e.to)+' (recovered)');});
  if(lines.length){phone('🔧 Overnight infra summary',lines.join('\n'),'infra_summary');log('[7am] '+lines.length+' item(s)');}
  context.set('ON',[]);
  return null;
}

var p=msg.payload||{};
var mon=(p.monitor&&p.monitor.name)||p.name;
if(!mon) return null;
if((p.monitor&&p.monitor.type==='group')||({'Infra':1,'Services':1,'Network':1})[mon]) return null;
var st=(p.heartbeat&&p.heartbeat.status); if(st===undefined&&p.status!==undefined)st=p.status;
var core=!!CORE[mon];
var S=context.get('S')||{};

if(st===0||st==='0'){
  if(S[mon]) return null;
  S[mon]={downSince:Date.now(),tier:0,core:core}; context.set('S',S);
  var T=context.get('T')||{}; T[mon]={}; context.set('T',T);
  log('[down-rcv] '+mon+(core?' (core)':''));
  T[mon].grace=setTimeout(function(){
    var S=context.get('S')||{}; if(!S[mon])return;
    S[mon].tier=1; context.set('S',S);
    if(quiet()){var ON=context.get('ON')||[];ON.push({type:'down',mon:mon,from:S[mon].downSince});context.set('ON',ON);log('[quiet] '+mon+' down held');}
    else{phone((core?'🔴':'⚠️')+' '+mon+' is DOWN',mon+' down ~90s (since '+hhmm(S[mon].downSince)+').','infra_'+mon);log('[tier1] '+mon);}
  },GRACE);
  T[mon].t2=setTimeout(function(){
    var S=context.get('S')||{}; if(!S[mon])return;
    S[mon].tier=2; context.set('S',S);
    if(quiet())return;
    phone((core?'🔴':'⚠️')+' '+mon+' STILL DOWN',mon+' down '+dur(Date.now()-S[mon].downSince)+'.','infra_'+mon);
    tts('Attention. '+mon+' has been down for '+durWords(Date.now()-S[mon].downSince)+'.');
    log('[tier2] '+mon+' phone+tts');
    var T=context.get('T')||{};
    if(T[mon]&&!T[mon].t3){var iv=(core||countDown()>=MULTI)?T3:T3_SLOW;
      T[mon].t3=setInterval(function(){
        var S=context.get('S')||{}; if(!S[mon])return; if(quiet())return;
        phone('🔴 '+mon+' STILL DOWN',mon+' down '+dur(Date.now()-S[mon].downSince)+'.','infra_'+mon);
        tts(mon+' is still down after '+durWords(Date.now()-S[mon].downSince)+'.');
        log('[tier3] '+mon+' repeat');
      },iv);
      context.set('T',T);
    }
  },T2);
  context.set('T',T);
}else if(st===1||st==='1'){
  if(!S[mon])return null;
  var ds=S[mon].downSince, tier=S[mon].tier;
  clr(mon); delete S[mon]; context.set('S',S);
  if(quiet()){var ON=context.get('ON')||[];ON.push({type:'recovered',mon:mon,from:ds,to:Date.now()});context.set('ON',ON);log('[quiet] '+mon+' recovered');}
  else if(tier>=1){phone('✅ '+mon+' recovered',mon+' back up after '+dur(Date.now()-ds)+'.','infra_'+mon);if(tier>=2)tts(mon+' is back online, after '+durWords(Date.now()-ds)+' down.');log('[recovered] '+mon+(tier>=2?' (+tts)':''));}
  else{log('[up] '+mon+' (within grace)');}
}
return null;

var p=msg.payload||{};
var ns=p.new_state&&p.new_state.state, os=p.old_state&&p.old_state.state;
if(ns!=='off'||os!=='on')return null;
return msg;

var map={};
((msg.payload&&msg.payload.publicGroupList)||[]).forEach(function(g){(g.monitorList||[]).forEach(function(m){map[m.id]=m.name;});});
msg.idmap=map;
delete msg.payload;delete msg.headers;
return msg;

var idmap=msg.idmap||{};
var hb=(msg.payload&&msg.payload.heartbeatList)||{};
var out=[];
for(var id in hb){var b=hb[id];if(!b||!b.length)continue;var last=b[b.length-1];
 if(last.status===1&&idmap[id]){out.push({payload:{heartbeat:{status:1,msg:'maintenance-off reconcile'},monitor:{name:idmap[id]}}});}}
var ts=new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});
return [out,[{payload:ts+'  [maint-off-reconcile] injected '+out.length+' up-events\n'}]];
